parameters.jsCode:
const raw = $input.first().json.output;

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    type: "UNKNOWN",
    calories: 0,
    protein: 0,
    calories_burned: 0,
    risk: "NONE",
    suggestion: "AI parsing failed",
    reply: "Sorry, I couldn't understand. Try again."
  };
}

// Get user data
let user = $('Fetch User Data').first().json;

let totalCalories = parseInt(user.Consumed_Calories || 0);
let protein = parseInt(user.Protein || 0);
let riskCount = parseInt(user.Risk_Count || 0);

// FOOD
if (parsed.type === "FOOD") {
  totalCalories += parsed.calories;
  protein += parsed.protein;
}

// ACTIVITY
if (parsed.type === "ACTIVITY") {
  totalCalories -= parsed.calories_burned;
}

// Risk tracking
if (parsed.risk !== "NONE") {
  riskCount += 1;
}

return [{
  json: {
    ...user,
    ...parsed,
    Consumed_Calories: totalCalories,
    Protein: protein,
    Risk_Count: riskCount,
    message: $('Receive User Input').first().json.body.message
  }
}];

